#include <stdio.h>
int max(int a, int b) { return a > b ? a : b; }
int main() {
    int T, n, i, j, coal[50], tax[50], policy[50], dp[50][50];
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (i = 0; i < n; i++) scanf("%d", &coal[i]);
        for (i = 0; i < n - 1; i++) scanf("%d", &tax[i]);
        for (i = 0; i < n - 1; i++) scanf("%d", &policy[i]);
        for (i = 0; i < n; i++) for (j = 0; j < n; j++) dp[i][j] = 0;
        for (i = 0; i < n; i++) dp[i][i] = coal[i];
        for (j = 1; j < n; j++) {
            for (i = 0; i < n - j; i++) {
                int k = i + j;
                dp[i][k] = max(dp[i][k], dp[i][k - 1] + coal[k] - (policy[k - 1] == 1 ? tax[k - 1] : 0));
                dp[i][k] = max(dp[i][k], dp[i + 1][k] + coal[i] - (policy[i] == 1 ? tax[i] : 0));
            }
        }
        printf("%d\n", dp[0][n - 1]);
    }
    return 0;
}

