import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] coal = new int[n];
            int[] tax = new int[n - 1];
            int[] policy = new int[n - 1];
            for (int i = 0; i < n; i++) coal[i] = sc.nextInt();
            for (int i = 0; i < n - 1; i++) tax[i] = sc.nextInt();
            for (int i = 0; i < n - 1; i++) policy[i] = sc.nextInt();
            int[][] dp = new int[n][n];
            for (int i = 0; i < n; i++) for (int j = 0; j < n; j++) dp[i][j] = 0;
            for (int i = 0; i < n; i++) dp[i][i] = coal[i];
            for (int j = 1; j < n; j++) {
                for (int i = 0; i < n - j; i++) {
                    int k = i + j;
                    dp[i][k] = Math.max(dp[i][k], dp[i][k - 1] + coal[k] - (policy[k - 1] == 1 ? tax[k - 1] : 0));
                    dp[i][k] = Math.max(dp[i][k], dp[i + 1][k] + coal[i] - (policy[i] == 1 ? tax[i] : 0));
                }
            }
            System.out.println(dp[0][n - 1]);
        }
    }
}

