const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function nextLine() { return lines[idx++]; }
function nextInt() { return parseInt(nextLine()); }
function nextInts() { return nextLine().split(' ').map(Number); }
function max_profit(coal, tax, policy) {
    let n = coal.length;
    let dp = Array(n).fill(0).map(() => Array(n).fill(0));
    for (let i = 0; i < n; i++) dp[i][i] = coal[i];
    for (let j = 1; j < n; j++) {
        for (let i = 0; i < n - j; i++) {
            let k = i + j;
            dp[i][k] = Math.max(dp[i][k], dp[i][k - 1] + coal[k] - (policy[k - 1] == 1 ? tax[k - 1] : 0));
            dp[i][k] = Math.max(dp[i][k], dp[i + 1][k] + coal[i] - (policy[i] == 1 ? tax[i] : 0));
        }
    }
    return dp[0][n - 1];
}
let T = nextInt();
while (T-- > 0) {
    let n = nextInt();
    let coal = nextInts();
    let tax = nextInts();
    let policy = nextInts();
